-- https://github.com/wg/wrk

local cards = {}

-- read from cards.txt 
-- cards.txt is generated by the benchmark runner, not over here
-- do this only once
local file = io.open("cards.txt", "r")
if file then
    for line in file:lines() do
        if line and line ~= "" then
            table.insert(cards, line)
        end
    end
    file:close()
else
    print("!! cards.txt not found.")
end

local thread_counter = 1

-- in main thread per thread
function setup(thread)
    thread:set("id", thread_counter)
    thread_counter = thread_counter + 1
end

-- per thread
function init(args)
    math.randomseed(os.time() + id)
end

-- per http request
function request()
    -- choose random card
    local left_card = cards[math.random(1, #cards)]
    local right_card = cards[math.random(1, #cards)]

    -- choose random print number
    local left_print = math.random(1, 999)
    local right_print = math.random(1, 999)

    -- build our not so beautiful path for request
    local path = string.format(
        "/render/drop?left=%s&right=%s&left_print=%d&right_print=%d",
        left_card,
        right_card,
        left_print,
        right_print
    )

    return wrk.format("GET", path)
end
